'use client';
import { useState } from 'react';
import { signInWithGoogle } from '../lib/auth';
import { useAuth } from '../context/AuthContext';

export default function Landing() {
  const { setUser }           = useAuth();
  const [modal,   setModal]   = useState(null);
  const [loading, setLoading] = useState(false);
  const [error,   setError]   = useState(null);

  const handleLogin = async () => {
    setLoading(true); setError(null);
    try {
      const userData = await signInWithGoogle();
      setUser(userData); setModal(null);
    } catch (err) {
      const code = err?.code || '';
      if (code === 'auth/popup-closed-by-user' || code === 'auth/cancelled-popup-request') {
        setError(null); // silently ignore — user just closed the popup
      } else {
        setError(err.message);
      }
    } finally {
      setLoading(false);
    }
  };

  return (
    <div style={{
      minHeight: '100vh', display: 'flex', flexDirection: 'column',
      background: 'linear-gradient(135deg, #0a4a2e 0%, #1a6b42 55%, #21854f 100%)',
      position: 'relative', overflow: 'hidden',
    }}>
      {/* Decorative blobs */}
      <div style={{ position:'absolute', top:'-10%', right:'-8%', width:500, height:500, borderRadius:'50%',
        background:'radial-gradient(circle, rgba(201,162,39,0.18) 0%, transparent 65%)', pointerEvents:'none' }} />
      <div style={{ position:'absolute', bottom:'-10%', left:'-8%', width:400, height:400, borderRadius:'50%',
        background:'radial-gradient(circle, rgba(255,255,255,0.04) 0%, transparent 70%)', pointerEvents:'none' }} />
      {/* Grid texture */}
      <div style={{ position:'absolute', inset:0, opacity:0.03,
        backgroundImage:'linear-gradient(rgba(255,255,255,0.5) 1px, transparent 1px), linear-gradient(90deg, rgba(255,255,255,0.5) 1px, transparent 1px)',
        backgroundSize:'40px 40px', pointerEvents:'none' }} />

      {/* Nav */}
      <nav style={{ position:'relative', zIndex:10, display:'flex', alignItems:'center', justifyContent:'space-between', padding:'24px 48px' }}>
        <div style={{ display:'flex', alignItems:'center', gap:12 }}>
          <img src="data:image/png;base64," alt="NEU Seal"
            style={{ width:48, height:48, borderRadius:'50%', objectFit:'cover',
              boxShadow:'0 4px 14px rgba(0,0,0,0.3)', border:'2px solid rgba(255,255,255,0.25)' }} />
          <div>
            <div className="font-display" style={{ fontWeight:700, color:'white', fontSize:15, lineHeight:1.2 }}>New Era University</div>
            <div style={{ color:'rgba(255,255,255,0.45)', fontSize:10, textTransform:'uppercase', letterSpacing:'0.08em' }}>Quezon City, Philippines</div>
          </div>
        </div>

      </nav>

      {/* Hero */}
      <div style={{ flex:1, display:'flex', flexDirection:'column', alignItems:'center', justifyContent:'center',
        padding:'40px 24px 60px', textAlign:'center', position:'relative', zIndex:5 }}>

        {/* Tag */}
        <div style={{ display:'inline-flex', alignItems:'center', gap:7, marginBottom:28,
          background:'rgba(201,162,39,0.18)', border:'1px solid rgba(201,162,39,0.4)',
          color:'#f0c84a', padding:'7px 18px', borderRadius:20, fontSize:11, fontWeight:600,
          letterSpacing:'0.1em', textTransform:'uppercase' }}>
          <span className="pulse" style={{ width:7, height:7, borderRadius:'50%', background:'#f0c84a', display:'inline-block' }} />
          Laboratory Room Management System
        </div>

        {/* Title */}
        <h1 className="font-display" style={{ fontSize:'clamp(52px,9vw,96px)', fontWeight:700,
          color:'white', lineHeight:1.0, marginBottom:16, letterSpacing:'-0.02em' }}>
          NEU <span style={{ color:'#f0c84a' }}>Lab</span><br />Logger
        </h1>

        <p style={{ color:'rgba(255,255,255,0.65)', maxWidth:520, lineHeight:1.7,
          marginBottom:52, fontSize:'clamp(14px,1.8vw,17px)' }}>
          A centralized platform for tracking laboratory usage, managing professor
          access, and maintaining institutional records at New Era University.
        </p>

        {/* Single Sign In button */}
        <button onClick={() => { setModal('login'); setError(null); }}
          style={{ display:'flex', alignItems:'center', gap:10, background:'white', color:'#0a4a2e',
            padding:'16px 44px', borderRadius:14, fontSize:16, fontWeight:700, border:'none', cursor:'pointer',
            boxShadow:'0 8px 28px rgba(0,0,0,0.25)', transition:'all 0.2s', fontFamily:'inherit' }}
          onMouseOver={e => e.currentTarget.style.transform='translateY(-2px)'}
          onMouseOut={e => e.currentTarget.style.transform='translateY(0)'}>
          <KeyIcon size={18} /> Sign In
        </button>


      </div>

      <div style={{ position:'relative', zIndex:5, textAlign:'center', paddingBottom:20, color:'rgba(255,255,255,0.25)', fontSize:12 }}>
        © 2025 New Era University – Office of the Registrar. All rights reserved.
      </div>

      {/* Modal */}
      {modal && (
        <div style={{ position:'fixed', inset:0, zIndex:50, display:'flex', alignItems:'center', justifyContent:'center',
          padding:20, background:'rgba(0,0,0,0.65)', backdropFilter:'blur(10px)' }}
          onClick={e => e.target === e.currentTarget && setModal(null)}>
          <div className="slide-up" style={{ background:'white', borderRadius:28, width:'100%', maxWidth:440,
            overflow:'hidden', boxShadow:'0 32px 80px rgba(0,0,0,0.25)' }}>

            {/* Modal header */}
            <div style={{ position:'relative', padding:'36px 36px 28px', textAlign:'center',
              background:'linear-gradient(135deg, #0a4a2e, #1a6b42)' }}>
              <button onClick={() => setModal(null)}
                style={{ position:'absolute', top:16, right:16, width:32, height:32, borderRadius:'50%',
                  background:'rgba(255,255,255,0.15)', border:'none', color:'white', cursor:'pointer',
                  display:'flex', alignItems:'center', justifyContent:'center', fontSize:16 }}>✕</button>
              <img src="data:image/png;base64," alt="NEU Seal"
                style={{ width:60, height:60, borderRadius:'50%', objectFit:'cover', margin:'0 auto 16px',
                  display:'block', border:'2px solid rgba(255,255,255,0.3)',
                  boxShadow:'0 4px 16px rgba(0,0,0,0.2)' }} />
              <h2 className="font-display" style={{ fontSize:26, fontWeight:700, color:'white', marginBottom:6 }}>
                NEU Lab Logger
              </h2>
              <p style={{ color:'rgba(255,255,255,0.6)', fontSize:13 }}>
                Sign in with your institutional account to continue
              </p>
            </div>

            {/* Modal body */}
            <div style={{ padding:36 }}>
              {error && (
                <div style={{ marginBottom:20, padding:'12px 16px', borderRadius:12, fontSize:13,
                  display:'flex', alignItems:'flex-start', gap:10, lineHeight:1.5,
                  background:'#fef2f2', border:'1px solid rgba(220,38,38,0.2)', color:'#7f1d1d' }}>
                  <span>⚠️</span><span>{error}</span>
                </div>
              )}

              {/* Google button — only sign-in method */}
              <button onClick={() => handleLogin()} disabled={loading}
                style={{ width:'100%', display:'flex', alignItems:'center', justifyContent:'center', gap:12,
                  padding:'15px 20px', borderRadius:12, border:'1.5px solid #e5e7eb', background:'white',
                  color:'#374151', fontWeight:600, fontSize:14, cursor: loading ? 'not-allowed' : 'pointer',
                  transition:'all 0.15s', fontFamily:'inherit',
                  boxShadow:'0 2px 8px rgba(0,0,0,0.06)', opacity: loading ? 0.65 : 1 }}
                onMouseOver={e => !loading && (e.currentTarget.style.borderColor='#1a6b42')}
                onMouseOut={e => (e.currentTarget.style.borderColor='#e5e7eb')}>
                <GoogleLogo />
                {loading ? 'Signing in…' : 'Continue with Google (@neu.edu.ph)'}
              </button>

              <div style={{ marginTop:16, padding:'12px 14px', borderRadius:12, fontSize:12, lineHeight:1.6,
                display:'flex', alignItems:'flex-start', gap:8,
                background:'#e8f5ee', border:'1px solid rgba(26,107,66,0.2)', color:'#1a6b42' }}>
                ℹ️ Only @neu.edu.ph institutional emails are accepted. Contact ICT for access issues.
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

function QrIcon({ size = 18 }) {
  return (
    <svg width={size} height={size} viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
      <rect x="3" y="3" width="7" height="7"/><rect x="14" y="3" width="7" height="7"/>
      <rect x="3" y="14" width="7" height="7"/>
      <path d="M14 14h3v3h-3zM17 17h3v3h-3zM14 20v1M20 14v1"/>
    </svg>
  );
}
function KeyIcon({ size = 18 }) {
  return (
    <svg width={size} height={size} viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
      <circle cx="7.5" cy="15.5" r="5.5"/>
      <path d="M21 2l-9.6 9.6M15.5 7.5l3 3"/>
    </svg>
  );
}
function GoogleLogo() {
  return (
    <svg width="18" height="18" viewBox="0 0 48 48">
      <path fill="#EA4335" d="M24 9.5c3.54 0 6.71 1.22 9.21 3.6l6.85-6.85C35.9 2.38 30.47 0 24 0 14.62 0 6.51 5.38 2.56 13.22l7.98 6.19C12.43 13.72 17.74 9.5 24 9.5z"/>
      <path fill="#4285F4" d="M46.98 24.55c0-1.57-.15-3.09-.38-4.55H24v9.02h12.94c-.58 2.96-2.26 5.48-4.78 7.18l7.73 6c4.51-4.18 7.09-10.36 7.09-17.65z"/>
      <path fill="#FBBC05" d="M10.53 28.59c-.48-1.45-.76-2.99-.76-4.59s.27-3.14.76-4.59l-7.98-6.19C.92 16.46 0 20.12 0 24c0 3.88.92 7.54 2.56 10.78l7.97-6.19z"/>
      <path fill="#34A853" d="M24 48c6.48 0 11.93-2.13 15.89-5.81l-7.73-6A7.16 7.16 0 0124 38.1a7.07 7.07 0 01-6.73-4.88l-7.98 6.19C13.1 43.83 18.41 48 24 48z"/>
    </svg>
  );
}
